class Solution {
    public String lastSubstring(String s) {
        int maxIndex = 0;
        for (int i = 1; i < s.length(); i++) {
            int j = 0;
            while (j + maxIndex < s.length() && s.charAt(j + maxIndex) == s.charAt(i + j)) {
                j++;
            }
            if (s.charAt(i + j) > s.charAt(maxIndex + j)) {
                maxIndex = i;
            }
        }
        return s.substring(maxIndex);
    }
}
